#include <iostream>
using namespace std;

int main() {
	int a,b,c,d;
	cin>>a>>b>>c>>d;
	if(a==b||a==c||a==d) {
		cout<<"NO\n";
		return 0;
	}
	for(int i=0; i<100; i++) {
		if(a-1!=b||a-1!=c||a-1!=d) {
			a-=1;
		} else if(a-2!=b||a-2!=c||a-2!=d) {
			a-=2;
		} else if(a-3!=b||a-3!=c||a-3!=d) {
			a-=3;
		}
		if(a==0) {
			cout<<"YES\n";
			return 0;
		}
	}
	if(a!=0) {
		cout<<"NO\n";
	}
	return 0;
}
